411→func (h *Handler) handleSetup(resp Response, req Request) Response {
412→	if req.File == "" {
413→		resp.Status = "error"
414→		resp.Code = ErrInvalidRequest
415→		resp.Message = "setup command requires a file path"
416→		return resp
417→	}
418→	if req.Scope == "" {
419→		resp.Status = "error"
420→		resp.Code = ErrInvalidRequest
421→		resp.Message = "setup command requires a scope"
422→		return resp
423→	}
424→	if !req.Level.IsValid() {
425→		resp.Status = "error"
426→		resp.Code = ErrInvalidRequest
427→		resp.Message = fmt.Sprintf("setup command requires a valid level, got %q", req.Level)
428→		return resp
429→	}
430→
431→	if _, err := os.Stat(req.File); err != nil {
432→		resp.Status = "error"
433→		resp.Code = ErrFileNotFound
434→		resp.Message = fmt.Sprintf("setup file not found: %s", req.File)
435→		return resp
436→	}
437→
438→	var parentCtxJSON json.RawMessage
439→	if req.ParentContext != nil {
440→		data, err := json.Marshal(req.ParentContext)
441→		if err != nil {
442→			resp.Status = "error"
443→			resp.Code = ErrInternalError
444→			resp.Message = fmt.Sprintf("marshaling parent context: %v", err)
445→			return resp
446→		}
447→		parentCtxJSON = data
448→	}
449→
450→	h.log.Debug("Running setup", "file", req.File, "scope", req.Scope, "level", req.Level)
451→
452→	ctx, err := h.setupLoader.RunSetup(req.File, req.Scope, string(req.Level), req.ProjectRoot, parentCtxJSON)
453→	if err != nil {
454→		resp.Status = "error"
455→		resp.Code = ErrInternalError
456→		resp.Message = fmt.Sprintf("setup failed: %v", err)
457→		return resp
458→	}
459→
460→	resp.Status = "setup"
461→	ctxCopy := json.RawMessage(ctx)
462→	resp.SetupContext = &ctxCopy
463→	return resp
464→}
465→
466→func (h *Handler) handleTeardown(resp Response, req Request) Response {
467→	if req.Scope == "" {
468→		resp.Status = "error"
469→		resp.Code = ErrInvalidRequest
470→		resp.Message = "teardown command requires a scope"
471→		return resp
472→	}
473→	if !req.Level.IsValid() {
474→		resp.Status = "error"
475→		resp.Code = ErrInvalidRequest
476→		resp.Message = fmt.Sprintf("teardown command requires a valid level, got %q", req.Level)
477→		return resp
478→	}
479→
480→	h.log.Debug("Running teardown", "scope", req.Scope, "level", req.Level)
481→
482→	h.setupLoader.Teardown(req.Scope, string(req.Level))
483→
484→	resp.Status = "teardown_ack"
485→	return resp
486→}
487→
488→func (h *Handler) handleGenerate(resp Response, req Request) Response {
489→	if req.File == "" {
490→		resp.Status = "error"
491→		resp.Code = ErrInvalidRequest
492→		resp.Message = "generate command requires a file path"
493→		return resp
494→	}
495→	if req.Name == "" {
496→		resp.Status = "error"
497→		resp.Code = ErrInvalidRequest
498→		resp.Message = "generate command requires a name"
499→		return resp
500→	}
501→
502→	var recipe json.RawMessage
503→	if req.Recipe != nil {
504→		recipe = *req.Recipe
505→	}
506→
507→	value, generatorID, outRecipe, err := h.registry.Generate(req.File, req.Name, recipe)
508→	if err != nil {
509→		resp.Status = "error"
510→		resp.Code = ErrInternalError
511→		resp.Message = fmt.Sprintf("generate failed: %v", err)
512→		return resp
513→	}
514→
515→	resp.Status = "generate"
516→	valCopy := json.RawMessage(value)
517→	resp.Value = &valCopy
518→	resp.GeneratorID = generatorID
519→	if outRecipe != nil {
520→		recipeCopy := json.RawMessage(outRecipe)
521→		resp.Recipe = &recipeCopy
522→	}
523→	return resp
524→}
525→
526→// Registry returns the generator registry, allowing custom builds to register
527→// native generators before calling Run().
528→func (h *Handler) Registry() *generators.Registry {
529→	return h.registry
530→}
531→
532→func (h *Handler) handleShutdown(resp Response) Response {
533→	h.registry.Close()
534→	h.setupLoader.Close()
535→	resp.Status = "shutdown_ack"
536→	return resp
537→}
538→
539→func (h *Handler) send(resp Response) error {
540→	data, err := json.Marshal(resp)
541→	if err != nil {
542→		return fmt.Errorf("marshaling response: %w", err)
543→	}
544→	line := string(data) + "\n"
545→	h.log.Log(context.Background(), LevelTrace, "Sent", "raw", string(data))
546→	_, err = io.WriteString(h.writer, line)
547→	return err
548→}
